func calc(a1 []int, t1 []int, a2 []int, t2 []int) int {
	minEnd := math.MaxInt32
	for i := 0; i < len(a1); i++ {
		minEnd = min(minEnd, a1[i]+t1[i])
	}
	ans := math.MaxInt32
	for i := 0; i < len(a2); i++ {
		ans = min(ans, max(minEnd, a2[i])+t2[i])
	}
	return ans
}

